import{_ as e,o as a,c as t,a2 as n}from"./chunks/framework.il0noOp3.js";const k=JSON.parse('{"title":"CAF/WAF Assessment Platform","description":"Run a read-only CAF/WAF landing-zone assessment with AzureScout — engine, layers, scoring, and report tiers.","frontmatter":{"description":"Run a read-only CAF/WAF landing-zone assessment with AzureScout — engine, layers, scoring, and report tiers."},"headers":[],"relativePath":"assessment.md","filePath":"assessment.md"}'),i={name:"assessment.md"};function r(l,s,o,d,h,p){return a(),t("div",null,[...s[0]||(s[0]=[n(`<h1 id="caf-waf-assessment-platform" tabindex="-1">CAF/WAF Assessment Platform <a class="header-anchor" href="#caf-waf-assessment-platform" aria-label="Permalink to &quot;CAF/WAF Assessment Platform&quot;">​</a></h1><p>Introduced in <strong>v2.0.0</strong>, AzureScout can score a tenant against the Microsoft <strong>Cloud Adoption Framework (CAF)</strong> design areas and <strong>Well-Architected Framework (WAF)</strong> pillars — not just inventory it. The assessment is <strong>read-only</strong> end to end (Reader at the management-group root + read-only Graph).</p><div class="tip custom-block"><p class="custom-block-title">PowerShell 7 required</p><p>The assessment platform requires <strong>PowerShell 7</strong>. The v1 inventory features (<code>Invoke-AzureScout</code>) still run on Windows PowerShell 5.1.</p></div><h2 id="architecture-—-three-layers-json-on-disk" tabindex="-1">Architecture — three layers, JSON on disk <a class="header-anchor" href="#architecture-—-three-layers-json-on-disk" aria-label="Permalink to &quot;Architecture — three layers, JSON on disk&quot;">​</a></h2><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>COLLECT  --collect.json--&gt;  ASSESS  --findings.json--&gt;  REPORT</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Each layer runs independently from its JSON input, so you can collect once and assess later, or re-render reports from an existing findings set without re-scanning.</p><table tabindex="0"><thead><tr><th>Layer</th><th>What it does</th></tr></thead><tbody><tr><td><strong>Collect</strong></td><td>Read-only Azure Resource Graph queries produce a normalized <code>collect.json</code>, including a per-domain <code>domains.*</code> namespace.</td></tr><tr><td><strong>Ingest</strong></td><td>Folds Azure Governance Visualizer, an ARG query pack, and Azure Advisor into the same <code>collect.json</code>.</td></tr><tr><td><strong>Assess</strong></td><td>A declarative rule engine grades the collected data — <strong>139 rules across 8 CAF design areas + 5 WAF pillars</strong> — producing scored <code>findings.json</code> with a prioritized gap list.</td></tr><tr><td><strong>Report</strong></td><td>Renders <code>findings.json</code> into tiered deliverables.</td></tr></tbody></table><h2 id="quick-start" tabindex="-1">Quick start <a class="header-anchor" href="#quick-start" aria-label="Permalink to &quot;Quick start&quot;">​</a></h2><div class="language-powershell vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Import-Module</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> .</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">AzureScout.psd1</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Full landing-zone assessment, every report tier</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Invoke-ScoutAssessment</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> -</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Assessment LandingZone </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">OutputFormat All</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Assess a single domain</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Invoke-ScoutAssessment</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> -</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Assessment Security </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">OutputFormat Html</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Collect once, assess later from the saved collect.json</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Invoke-ScoutAssessment</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> -</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Assessment LandingZone </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">CollectOnly</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Invoke-ScoutAssessment</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> -</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Assessment LandingZone </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">FromCollect .</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">output</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/&lt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">run</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">collect.json </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">OutputFormat PowerBi</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br></div></div><p>Every discovery category is an independently runnable, tagged assessment — pass one, several, or <code>All</code> to <code>-Assessment</code>.</p><h2 id="scoring" tabindex="-1">Scoring <a class="header-anchor" href="#scoring" aria-label="Permalink to &quot;Scoring&quot;">​</a></h2><ul><li>Each rule evaluates to <strong>Pass</strong>, <strong>Fail</strong>, <strong>Partial</strong>, <strong>Manual</strong>, <strong>Unknown</strong>, or <strong>Error</strong>.</li><li>Framework scores are the rule-count-weighted roll-up of area/pillar scores.</li><li><code>Unknown</code>/<code>Error</code> are surfaced, never silently dropped — a broken rule cannot inflate a score.</li><li>The <strong><code>Manual</code></strong> status intentionally hands the un-automatable checks to a human, with the collected evidence already attached.</li></ul><h2 id="report-tiers" tabindex="-1">Report tiers <a class="header-anchor" href="#report-tiers" aria-label="Permalink to &quot;Report tiers&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Tier</th><th>Output</th><th>Notes</th></tr></thead><tbody><tr><td>Power BI</td><td><code>powerbi/*.csv</code> + <code>.pbit</code></td><td>Primary analytics tier (star schema)</td></tr><tr><td>HTML</td><td><code>report.html</code></td><td>Self-contained, single file</td></tr><tr><td>PowerPoint</td><td><code>assessment_deck.pptx</code></td><td>Executive deck via the OpenXML SDK — <strong>no Python dependency</strong></td></tr><tr><td>Excel</td><td><code>assessment_evidence.xlsx</code></td><td>Evidence tier</td></tr><tr><td>JSON</td><td><code>findings.json</code></td><td>The machine-readable contract</td></tr></tbody></table><h2 id="permission-pre-flight" tabindex="-1">Permission pre-flight <a class="header-anchor" href="#permission-pre-flight" aria-label="Permalink to &quot;Permission pre-flight&quot;">​</a></h2><div class="language-powershell vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Invoke-ScoutAssessment</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> -</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Assessment LandingZone </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">PermissionAudit</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Reports whether the current identity has the read-only access each selected assessment needs, before any collection runs.</p><h2 id="design-reference" tabindex="-1">Design reference <a class="header-anchor" href="#design-reference" aria-label="Permalink to &quot;Design reference&quot;">​</a></h2><p>The full architecture, rule catalogue, and decision records live in the <a href="./design/master-plan.html">Master Design &amp; Plan</a> and the <a href="./design/assessment-registry.html">assessment registry</a>.</p>`,19)])])}const g=e(i,[["render",r]]);export{k as __pageData,g as default};
